const data = $input.first().json.data || $input.first().json;
const emails = Array.isArray(data) ? data : (data.emails || []);

const techKeywords = [
  'engineer', 'engineering', 'cto', 'technical', 
  'frontend', 'backend', 'software', 'web', 
  'developer', 'architect', 'devops', 'infrastructure'
];

const blockedTitles = [
  'sales', 'marketing', 'finance', 'legal', 
  'product management', 'account', 'recruiter',
  'human resources', 'operations', 'risk',
  'business', 'revenue', 'growth'
];

const filtered = emails.filter(person => {
  const title = (person.position || '').toLowerCase();

  const isBlocked = blockedTitles.some(b => title.includes(b));
  if (isBlocked) return false;

  const isTech = techKeywords.some(kw => title.includes(kw));
  const isDeptTech = ['it', 'engineering'].includes(
    (person.department || '').toLowerCase()
  );

  return isTech || isDeptTech;
});

return filtered.map(person => ({ json: person }));
